import { z } from 'zod';

/**
 * Viewport configuration for screenshot capture and CDP device emulation.
 *
 * Supports predefined names or custom dimensions. Optional fields control
 * full device emulation via Emulation.setDeviceMetricsOverride +
 * setUserAgentOverride + setTouchEmulationEnabled. When the preset has
 * `mobile: true` and no `userAgent`, callers (e.g. devices.ts) should
 * supply a mobile UA — leaving Chrome's desktop UA on a mobile viewport
 * is the documented "renders at desktop" bug pre-1.1.0.
 */
export const ViewportSchema = z.object({
  name: z.string().min(1).max(50),
  width: z.number().min(100).max(3840),
  height: z.number().min(100).max(2160),
  deviceScaleFactor: z.number().min(0.5).max(5).optional(),
  mobile: z.boolean().optional(),
  userAgent: z.string().optional(),
  hasTouch: z.boolean().optional(),
});

/**
 * Predefined viewport configurations.
 *
 * `mobile` and `tablet` baselines were realigned in 1.1.0:
 *   - mobile: 375x667 (iPhone SE) -> 390x844 (iPhone 14) with mobile:true
 *   - tablet: 768x1024 (iPad Mini) -> 820x1180 (iPad Air) with mobile:true
 * Pre-1.1.0 these presets were missing the `mobile` flag entirely so Chrome
 * laid the page out as desktop. See VERSIONING.md.
 */
export const VIEWPORTS = {
  desktop: { name: 'desktop', width: 1920, height: 1080, deviceScaleFactor: 1, mobile: false },
  'desktop-lg': { name: 'desktop-lg', width: 2560, height: 1440, deviceScaleFactor: 1, mobile: false },
  'desktop-sm': { name: 'desktop-sm', width: 1440, height: 900, deviceScaleFactor: 1, mobile: false },
  laptop: { name: 'laptop', width: 1366, height: 768, deviceScaleFactor: 1, mobile: false },
  tablet: { name: 'tablet', width: 820, height: 1180, deviceScaleFactor: 2, mobile: true },
  'tablet-landscape': { name: 'tablet-landscape', width: 1180, height: 820, deviceScaleFactor: 2, mobile: true },
  mobile: { name: 'mobile', width: 390, height: 844, deviceScaleFactor: 3, mobile: true },
  'mobile-lg': { name: 'mobile-lg', width: 430, height: 932, deviceScaleFactor: 3, mobile: true },
  'iphone-14': { name: 'iphone-14', width: 390, height: 844, deviceScaleFactor: 3, mobile: true },
  'iphone-14-pro-max': { name: 'iphone-14-pro-max', width: 430, height: 932, deviceScaleFactor: 3, mobile: true },
  // Native simulator viewports
  'iphone-16': { name: 'iphone-16', width: 393, height: 852 },
  'iphone-16-plus': { name: 'iphone-16-plus', width: 430, height: 932 },
  'iphone-16-pro': { name: 'iphone-16-pro', width: 402, height: 874 },
  'iphone-16-pro-max': { name: 'iphone-16-pro-max', width: 440, height: 956 },
  'watch-series-10-42mm': { name: 'watch-series-10-42mm', width: 176, height: 215 },
  'watch-series-10-46mm': { name: 'watch-series-10-46mm', width: 198, height: 242 },
  'watch-ultra-2-49mm': { name: 'watch-ultra-2-49mm', width: 205, height: 251 },
} as const;

/**
 * Provenance basis for a numeric verdict threshold.
 * - `research`: value derived from a published standard / study / vendor doc (cite `source`).
 * - `internal-testing`: value calibrated against our own labelled samples.
 * - `hypothesis`: an undocumented heuristic with no measurement behind it (yet).
 */
export const ThresholdBasisSchema = z.enum(['research', 'internal-testing', 'hypothesis']);

/**
 * A numeric verdict boundary carrying its own provenance, so no threshold can
 * ship as a bare magic number. `reviewedAt` (ISO date) sets a regular-review
 * expectation; `source` cites the evidence when `basis` is `research`.
 */
export const ProvenancedThresholdSchema = z.object({
  value: z.number(),
  basis: ThresholdBasisSchema,
  rationale: z.string().min(1),
  source: z.string().optional(),
  reviewedAt: z.string(),
});

/**
 * The complete set of numeric boundaries used by the comparison/verdict path.
 * Every field is a provenanced threshold — analyzeComparison/detectChangedRegions
 * read boundaries only from here, never from inline literals.
 */
export const VerdictPolicySchema = z.object({
  /** Regions with changed-pixel share at or below this are not reported (noise floor). */
  regionReportFloorPercent: ProvenancedThresholdSchema,
  /** Region change above this → 'critical' severity (drives LAYOUT_BROKEN). */
  regionCriticalPercent: ProvenancedThresholdSchema,
  /** Region change above this (and ≤ critical) → 'unexpected' severity. */
  regionUnexpectedPercent: ProvenancedThresholdSchema,
  /** Overall diff above this → UNEXPECTED_CHANGE even with no unexpected region. */
  unexpectedOverallPercent: ProvenancedThresholdSchema,
  /** Overall diff above this → fallback region location 'full' (else 'center'); presentation only. */
  fullFrameFallbackPercent: ProvenancedThresholdSchema,
  /** Verdict tolerance: overall diff at/below this stays EXPECTED and is never escalated to unexpected. */
  allowedDiffPercent: ProvenancedThresholdSchema,
});

/**
 * A partial override for a single threshold: a bare number overrides only the
 * value (provenance inherited from the preset), or a partial provenance object.
 */
export const ThresholdOverrideSchema = z.union([
  z.number(),
  ProvenancedThresholdSchema.partial(),
]);

/**
 * A partial verdict-policy override deep-merged onto a preset. Any subset of
 * threshold keys; each value a {@link ThresholdOverrideSchema}.
 */
export const VerdictPolicyOverrideSchema = z.object({
  regionReportFloorPercent: ThresholdOverrideSchema.optional(),
  regionCriticalPercent: ThresholdOverrideSchema.optional(),
  regionUnexpectedPercent: ThresholdOverrideSchema.optional(),
  unexpectedOverallPercent: ThresholdOverrideSchema.optional(),
  fullFrameFallbackPercent: ThresholdOverrideSchema.optional(),
  allowedDiffPercent: ThresholdOverrideSchema.optional(),
});

/**
 * Main configuration for InterfaceBuiltRight
 */
export const ConfigSchema = z.object({
  baseUrl: z.string().url('Must be a valid URL'),
  outputDir: z.string().default('./.ibr'),
  viewport: ViewportSchema.default(VIEWPORTS.desktop),
  viewports: z.array(ViewportSchema).optional(), // Multi-viewport support
  /** Verdict tolerance: overall diff percent (0-100) treated as an acceptable change. */
  allowedDiffPercent: z.number().min(0).max(100).optional(),
  /**
   * Per-project verdict-policy override (deep-merged onto the app-type preset,
   * beneath any per-call override). Lets an `.ibr` config tune verdict
   * boundaries for the whole project.
   */
  verdictPolicy: VerdictPolicyOverrideSchema.optional(),
  /** Pixelmatch per-pixel color sensitivity (0-1, lower = stricter). Default 0.1. */
  pixelColorThreshold: z.number().min(0).max(1).default(0.1),
  /** @deprecated Backward-compatible alias for `allowedDiffPercent` (verdict tolerance). */
  threshold: z.number().min(0).max(100).default(1.0),
  fullPage: z.boolean().default(true),
  waitForNetworkIdle: z.boolean().default(true),
  timeout: z.number().min(1000).max(120000).default(30000),
  browserMode: z.enum(['local', 'connect']).optional(),
  cdpUrl: z.string().url().optional(),
  wsEndpoint: z.string().url().optional(),
  chromePath: z.string().optional(),
});

/**
 * Session query options
 */
export const SessionQuerySchema = z.object({
  route: z.string().optional(),
  url: z.string().optional(),
  status: z.enum(['baseline', 'compared', 'pending']).optional(),
  name: z.string().optional(),
  createdAfter: z.date().optional(),
  createdBefore: z.date().optional(),
  viewport: z.string().optional(),
  limit: z.number().min(1).max(100).default(50),
});

/**
 * Comparison result from pixelmatch
 */
export const ComparisonResultSchema = z.object({
  match: z.boolean(),
  diffPercent: z.number(),
  diffPixels: z.number(),
  totalPixels: z.number(),
  /** @deprecated Mirrors `pixelColorThreshold` for backward compatibility. */
  threshold: z.number(),
  /** Pixelmatch per-pixel color sensitivity (0-1) used for this comparison. */
  pixelColorThreshold: z.number().optional(),
});

/**
 * Changed region detected in comparison
 */
export const ChangedRegionSchema = z.object({
  location: z.enum(['top', 'bottom', 'left', 'right', 'center', 'full']),
  bounds: z.object({
    x: z.number(),
    y: z.number(),
    width: z.number(),
    height: z.number(),
  }),
  description: z.string(),
  severity: z.enum(['expected', 'unexpected', 'critical']),
  /**
   * Raw measured change for this region, as a numeric percentage (0-100).
   * Additive structured field so a downstream agent can re-judge severity under
   * a different policy without parsing it out of `description`. Optional for
   * back-compat with previously-serialized regions.
   */
  diffPercent: z.number().optional(),
});

/**
 * Analysis verdict types
 */
export const VerdictSchema = z.enum([
  'MATCH',
  'EXPECTED_CHANGE',
  'UNEXPECTED_CHANGE',
  'LAYOUT_BROKEN',
]);

/**
 * Analysis result
 */
export const AnalysisSchema = z.object({
  verdict: VerdictSchema,
  summary: z.string(),
  changedRegions: z.array(ChangedRegionSchema),
  unexpectedChanges: z.array(ChangedRegionSchema),
  recommendation: z.string().nullable(),
  /**
   * The verdict policy actually applied (values + basis + rationale). Echoing it
   * lets a downstream agent see which boundaries drove this verdict and their
   * provenance — e.g. that a cutoff is `basis: 'hypothesis'`, not ground truth —
   * and re-judge under different thresholds without re-running the comparison.
   * Optional for back-compat with previously-serialized analyses.
   */
  policy: VerdictPolicySchema.optional(),
});

/**
 * Session status
 */
export const SessionStatusSchema = z.enum(['baseline', 'compared', 'pending']);

/**
 * Element bounds (moved up for LandmarkElementSchema dependency)
 */
export const BoundsSchema = z.object({
  x: z.number(),
  y: z.number(),
  width: z.number(),
  height: z.number(),
});

/**
 * Landmark element detected on page
 */
export const LandmarkElementSchema = z.object({
  name: z.string(),           // e.g., 'logo', 'header', 'nav'
  selector: z.string(),       // CSS selector used to find it
  found: z.boolean(),
  bounds: BoundsSchema.optional(),
});

/**
 * Visual session
 */
export const SessionSchema = z.object({
  id: z.string(),
  name: z.string(),
  url: z.string().min(1),
  viewport: ViewportSchema,
  status: SessionStatusSchema,
  platform: z.enum(['web', 'ios', 'watchos']).optional(),
  createdAt: z.string().datetime(),
  updatedAt: z.string().datetime(),
  comparison: ComparisonResultSchema.optional(),
  analysis: AnalysisSchema.optional(),
  // Landmark elements detected at baseline capture
  landmarkElements: z.array(LandmarkElementSchema).optional(),
  // Page intent detected at baseline
  pageIntent: z.string().optional(),
});

/**
 * Full comparison report
 */
export const ComparisonReportSchema = z.object({
  sessionId: z.string(),
  sessionName: z.string(),
  url: z.string(),
  timestamp: z.string().datetime(),
  viewport: ViewportSchema,
  comparison: ComparisonResultSchema,
  analysis: AnalysisSchema,
  files: z.object({
    baseline: z.string(),
    current: z.string(),
    diff: z.string(),
  }),
  webViewUrl: z.string().optional(),
});

/**
 * Element interactivity detection
 */
export const InteractiveStateSchema = z.object({
  hasOnClick: z.boolean(),
  hasHref: z.boolean(),
  isDisabled: z.boolean(),
  tabIndex: z.number(),
  cursor: z.string(),
  // Framework-specific detection
  hasReactHandler: z.boolean().optional(),
  hasVueHandler: z.boolean().optional(),
  hasAngularHandler: z.boolean().optional(),
});

/**
 * Accessibility attributes
 */
export const A11yAttributesSchema = z.object({
  role: z.string().nullable(),
  ariaLabel: z.string().nullable(),
  ariaDescribedBy: z.string().nullable(),
  ariaHidden: z.boolean().optional(),
  // WAI-ARIA aria-haspopup signals that activating the element opens a
  // menu/dialog/listbox/tree/grid. Headless component libraries (Radix,
  // Headless UI, Reach) wire the click via portal/event delegation rather
  // than a direct `onClick`, which trips the `no-handler` rule's heuristic.
  // Captured here so rules can opt out of grading these as orphans.
  ariaHaspopup: z.string().nullable().optional(),
});

/**
 * Enhanced element with interactivity and accessibility
 */
export const EnhancedElementSchema = z.object({
  // Identity
  selector: z.string(),
  tagName: z.string(),
  id: z.string().optional(),
  className: z.string().optional(),
  text: z.string().optional(),

  // Position
  bounds: BoundsSchema,

  // Styles (subset)
  computedStyles: z.record(z.string(), z.string()).optional(),

  // Interactivity
  interactive: InteractiveStateSchema,

  // True when the element is descendant of a <form>. A `<button>` inside a
  // form defaults to `type="submit"`, so its click is wired by the form's
  // submit pipeline rather than a direct onClick prop. Rules that check for
  // orphan handlers should treat in-form buttons as "wired by form" unless
  // their type is explicitly "button".
  inForm: z.boolean().optional(),
  buttonType: z.string().nullable().optional(),

  // Accessibility
  a11y: A11yAttributesSchema,

  // Source hints for debugging
  sourceHint: z.object({
    dataTestId: z.string().nullable(),
  }).optional(),
});

/**
 * Element issue detected during audit
 */
export const ElementIssueSchema = z.object({
  type: z.enum([
    'NO_HANDLER',           // Interactive-looking but no handler
    'PLACEHOLDER_LINK',     // href="#" without handler
    'TOUCH_TARGET_SMALL',   // < 44px on mobile
    'MISSING_ARIA_LABEL',   // Interactive without label
    'DISABLED_NO_VISUAL',   // Disabled but no visual indication
  ]),
  severity: z.enum(['error', 'warning', 'info']),
  message: z.string(),
});

/**
 * Audit result for a captured page
 */
export const AuditResultSchema = z.object({
  totalElements: z.number(),
  interactiveCount: z.number(),
  withHandlers: z.number(),
  withoutHandlers: z.number(),
  issues: z.array(ElementIssueSchema),
});

// Type exports - auto-generated from schemas
export type Viewport = z.infer<typeof ViewportSchema>;
export type Config = z.infer<typeof ConfigSchema>;
export type SessionQuery = z.infer<typeof SessionQuerySchema>;
export type ComparisonResult = z.infer<typeof ComparisonResultSchema>;
export type ChangedRegion = z.infer<typeof ChangedRegionSchema>;
export type Verdict = z.infer<typeof VerdictSchema>;
export type Analysis = z.infer<typeof AnalysisSchema>;
export type ThresholdBasis = z.infer<typeof ThresholdBasisSchema>;
export type ProvenancedThreshold = z.infer<typeof ProvenancedThresholdSchema>;
export type VerdictPolicy = z.infer<typeof VerdictPolicySchema>;
export type ThresholdOverride = z.infer<typeof ThresholdOverrideSchema>;
export type VerdictPolicyOverride = z.infer<typeof VerdictPolicyOverrideSchema>;
export type SessionStatus = z.infer<typeof SessionStatusSchema>;
export type LandmarkElement = z.infer<typeof LandmarkElementSchema>;
export type Session = z.infer<typeof SessionSchema>;
export type ComparisonReport = z.infer<typeof ComparisonReportSchema>;
export type InteractiveState = z.infer<typeof InteractiveStateSchema>;
export type A11yAttributes = z.infer<typeof A11yAttributesSchema>;
export type Bounds = z.infer<typeof BoundsSchema>;
export type EnhancedElement = z.infer<typeof EnhancedElementSchema>;
export type ElementIssue = z.infer<typeof ElementIssueSchema>;
export type AuditResult = z.infer<typeof AuditResultSchema>;

/**
 * Rule severity levels
 */
export const RuleSeveritySchema = z.enum(['off', 'warn', 'error']);

/**
 * Individual rule setting
 */
export const RuleSettingSchema = z.union([
  RuleSeveritySchema,
  z.tuple([RuleSeveritySchema, z.record(z.string(), z.unknown())]),
]);

/**
 * Rules configuration (user's .ibr/rules.json)
 */
export const RulesConfigSchema = z.object({
  extends: z.array(z.string()).optional(),
  rules: z.record(z.string(), RuleSettingSchema).optional(),
});

/**
 * Violation detected by a rule
 */
export const ViolationSchema = z.object({
  ruleId: z.string(),
  ruleName: z.string(),
  severity: z.enum(['warn', 'error']),
  message: z.string(),
  element: z.string().optional(),  // Selector of violating element
  bounds: BoundsSchema.optional(),
  fix: z.string().optional(),       // Suggested fix
});

/**
 * Full audit report with rule violations
 */
export const RuleAuditResultSchema = z.object({
  url: z.string(),
  timestamp: z.string(),
  elementsScanned: z.number(),
  violations: z.array(ViolationSchema),
  summary: z.object({
    errors: z.number(),
    warnings: z.number(),
    passed: z.number(),
  }),
});

// Rule-related type exports
export type RuleSeverity = z.infer<typeof RuleSeveritySchema>;
export type RuleSetting = z.infer<typeof RuleSettingSchema>;
export type RulesConfig = z.infer<typeof RulesConfigSchema>;
export type Violation = z.infer<typeof ViolationSchema>;
export type RuleAuditResult = z.infer<typeof RuleAuditResultSchema>;

// ============================================================================
// MEMORY SYSTEM SCHEMAS
// ============================================================================

/**
 * Source of a UI/UX preference
 */
export const MemorySourceSchema = z.enum(['user', 'learned', 'framework']);

/**
 * Preference categories
 */
export const PreferenceCategorySchema = z.enum([
  'color',
  'layout',
  'typography',
  'navigation',
  'component',
  'spacing',
  'interaction',
  'content',
]);

/**
 * Expectation operator for comparing values
 */
export const ExpectationOperatorSchema = z.enum(['equals', 'contains', 'matches', 'gte', 'lte']);

/**
 * A single UI/UX expectation
 */
export const ExpectationSchema = z.object({
  property: z.string(),
  operator: ExpectationOperatorSchema,
  value: z.string(),
});

/**
 * Full preference with history
 */
export const PreferenceSchema = z.object({
  id: z.string(),
  description: z.string(),
  category: PreferenceCategorySchema,
  source: MemorySourceSchema,
  route: z.string().optional(),
  componentType: z.string().optional(),
  expectation: ExpectationSchema,
  confidence: z.number().min(0).max(1).default(1.0),
  createdAt: z.string().datetime(),
  updatedAt: z.string().datetime(),
  sessionIds: z.array(z.string()).optional(),
});

/**
 * Observation extracted from a session
 */
export const ObservationSchema = z.object({
  description: z.string(),
  category: PreferenceCategorySchema,
  property: z.string(),
  value: z.string(),
});

/**
 * Learned expectation from an approved session
 */
export const LearnedExpectationSchema = z.object({
  id: z.string(),
  sessionId: z.string(),
  route: z.string(),
  observations: z.array(ObservationSchema),
  approved: z.boolean(),
  createdAt: z.string().datetime(),
});

/**
 * Compact preference pointer for summary
 */
export const ActivePreferenceSchema = z.object({
  id: z.string(),
  description: z.string(),
  category: PreferenceCategorySchema,
  route: z.string().optional(),
  componentType: z.string().optional(),
  property: z.string(),
  operator: ExpectationOperatorSchema,
  value: z.string(),
  confidence: z.number(),
});

/**
 * Memory summary - always-loaded compact file
 */
export const MemorySummarySchema = z.object({
  version: z.literal(1),
  updatedAt: z.string().datetime(),
  stats: z.object({
    totalPreferences: z.number(),
    totalLearned: z.number(),
    byCategory: z.record(z.string(), z.number()),
    bySource: z.record(z.string(), z.number()),
  }),
  activePreferences: z.array(ActivePreferenceSchema),
});

// Memory type exports
export type MemorySource = z.infer<typeof MemorySourceSchema>;
export type PreferenceCategory = z.infer<typeof PreferenceCategorySchema>;
export type ExpectationOperator = z.infer<typeof ExpectationOperatorSchema>;
export type Expectation = z.infer<typeof ExpectationSchema>;
export type Preference = z.infer<typeof PreferenceSchema>;
export type Observation = z.infer<typeof ObservationSchema>;
export type LearnedExpectation = z.infer<typeof LearnedExpectationSchema>;
export type ActivePreference = z.infer<typeof ActivePreferenceSchema>;
export type MemorySummary = z.infer<typeof MemorySummarySchema>;

// ============================================================================
// DESIGN SYSTEM SCHEMAS
// ============================================================================

/**
 * Design system principle violation
 */
export const DesignSystemViolationSchema = z.object({
  principleId: z.string(),
  principleName: z.string(),
  severity: z.enum(['error', 'warn']),
  message: z.string(),
  element: z.string().optional(),
  bounds: BoundsSchema.optional(),
  fix: z.string().optional(),
});

/**
 * Design system check result (added to ScanResult)
 */
export const DesignSystemResultSchema = z.object({
  configName: z.string(),
  principleViolations: z.array(DesignSystemViolationSchema),
  tokenViolations: z.array(z.object({
    element: z.string(),
    property: z.string(),
    expected: z.union([z.string(), z.number()]),
    actual: z.union([z.string(), z.number()]),
    severity: z.enum(['error', 'warning']),
    message: z.string(),
  })),
  customViolations: z.array(DesignSystemViolationSchema),
  complianceScore: z.number().min(0).max(100),
});

// Design system type exports
export type DesignSystemViolation = z.infer<typeof DesignSystemViolationSchema>;
export type DesignSystemResult = z.infer<typeof DesignSystemResultSchema>;
